scripts.content:
extends Node

signal time_changed(time_of_day: float)  ## 0.0–1.0
signal period_changed(period: String)     ## "dawn", "day", "dusk", "night"
signal weather_changed(weather: String)

@export var day_length_seconds: float = {{day_length_seconds}}

var _time_of_day: float = {{start_time}}  ## 0.0 (midnight) → 0.5 (noon) → 1.0 (midnight)
var _current_period: String = "day"
var _paused: bool = false

@onready var _sun_light: DirectionalLight3D = $SunLight
@onready var _ambient_light: WorldEnvironment = $"../WorldEnvironment"

func _ready():
	_setup_lighting()

func _process(delta: float) -> void:
	if _paused:
		return

	_time_of_day += delta / day_length_seconds
	if _time_of_day >= 1.0:
		_time_of_day -= 1.0

	_update_sun_position()
	_update_lighting()
	_check_period()
	time_changed.emit(_time_of_day)

func get_time_of_day() -> float:
	return _time_of_day

func get_hour() -> int:
	return int(_time_of_day * 24.0)

func get_minute() -> int:
	return int((_time_of_day * 24.0 - get_hour()) * 60.0)

func get_period() -> String:
	return _current_period

func is_daytime() -> bool:
	return _time_of_day > 0.25 and _time_of_day < 0.75

func is_nighttime() -> bool:
	return not is_daytime()

func set_time(time: float) -> void:
	_time_of_day = clamp(time, 0.0, 0.999)
	_update_sun_position()
	_update_lighting()
	_check_period()

func set_paused(paused: bool) -> void:
	_paused = paused

func add_time(hours: float) -> void:
	_time_of_day += hours / 24.0
	if _time_of_day >= 1.0:
		_time_of_day -= 1.0

func set_weather(weather: String) -> void:
	weather_changed.emit(weather)

func _update_sun_position() -> void:
	# 0° at midnight (nadir), 180° (PI) at noon (zenith)
	_sun_light.rotation.x = _time_of_day * PI * 2.0

func _update_lighting() -> void:
	# -cos(t*2PI) peaks at noon (1.0), troughs at midnight (-1.0)
	var sun_height := -cos(_time_of_day * PI * 2.0)
	_sun_light.light_energy = max(0.0, sun_height * 1.5)

	var day_factor := clamp(sun_height, 0.0, 1.0)
	var night_c := Color({{night_color.x}}, {{night_color.y}}, {{night_color.z}})
	var day_c := Color({{day_color.x}}, {{day_color.y}}, {{day_color.z}})
	var sky_color := night_c.lerp(day_c, day_factor)

	var amb_energy := lerp({{ambient_min}}, {{ambient_max}}, day_factor)

	if _ambient_light:
		var env := _ambient_light.environment
		if env:
			env.ambient_light_color = sky_color
			env.ambient_light_energy = amb_energy

func _check_period() -> void:
	var prev := _current_period
	var t := _time_of_day
	if t < 0.2:
		_current_period = "night"
	elif t < 0.3:
		_current_period = "dawn"
	elif t < 0.7:
		_current_period = "day"
	elif t < 0.8:
		_current_period = "dusk"
	else:
		_current_period = "night"

	if prev != _current_period:
		period_changed.emit(_current_period)

func _setup_lighting() -> void:
	_sun_light.shadow_enabled = true
	_sun_light.directional_shadow_mode = DirectionalLight3D.SHADOW_PARALLEL_4_SPLITS
	_update_sun_position()
	_update_lighting()
	_check_period()

func serialize() -> Dictionary:
	return {"time_of_day": _time_of_day}

func deserialize(data: Dictionary) -> void:
	_time_of_day = data.get("time_of_day", 0.25)
	_update_sun_position()
	_update_lighting()
